108	func (s *service) quotaRefreshPolicy() quotaRefreshPolicy {
109		policy := quotaRefreshPolicy{
110			debounce:     defaultQuotaRefreshDebounce,
111			startupWait:  defaultQuotaRefreshStartupWait,
112			probeTimeout: defaultQuotaRefreshProbeTimeout,
113		}
114		if s != nil {
115			if s.opts.QuotaRefreshDebounce > 0 {
116				policy.debounce = s.opts.QuotaRefreshDebounce
117			}
118			if s.opts.QuotaRefreshStartupWait > 0 {
119				policy.startupWait = s.opts.QuotaRefreshStartupWait
120			}
121		}
122		return policy
123	}
