248	// ListProviders returns providers known to the native fiz harness with live
249	// status, configured-default markers, and cooldown state.
250	func (s *service) ListProviders(ctx context.Context) ([]ProviderInfo, error) {
251		sc := s.opts.ServiceConfig
252		if sc == nil {
253			return nil, fmt.Errorf("service: no ServiceConfig provided; pass ServiceOptions.ServiceConfig")
254		}
255	
256		names := sc.ProviderNames()
257		defaultName := sc.DefaultProviderName()
258		cooldown := sc.HealthCooldown()
259		if cooldown <= 0 {
260			cooldown = 30 * time.Second
261		}
262	
263		type indexedInfo struct {
264			idx  int
265			info ProviderInfo
266		}
267		results := make([]indexedInfo, len(names))
268		var wg sync.WaitGroup
269	
270		for i, name := range names {
271			wg.Add(1)
272			go func(idx int, name string) {
273				defer wg.Done()
274	
275				entry, ok := sc.Provider(name)
276				if !ok {
277					results[idx] = indexedInfo{idx: idx, info: ProviderInfo{
278						Name:   name,
279						Status: "error: provider not found in config",
280					}}
281					return
282				}
283	
284				info := ProviderInfo{
285					Name:             name,
286					Type:             normalizeServiceProviderType(entry.Type),
287					BaseURL:          entry.BaseURL,
288					Endpoints:        append([]ServiceProviderEndpoint(nil), entry.Endpoints...),
289					Billing:          serviceProviderBilling(entry),
290					IncludeByDefault: serviceProviderDefaultInclusion(entry),
291					IsDefault:        name == defaultName,
292					DefaultModel:     entry.Model,
293				}
294	
295				if entry.ConfigError != "" {
296					capturedAt := time.Now().UTC()
297					info.Status = "error: invalid provider config"
298					info.EndpointStatus = providerEndpointStatusesFromProbe(entry, providerProbeResult{
299						status: "error: invalid provider config",
300						detail: entry.ConfigError,
301					}, capturedAt)
302					info.Auth = providerAuthStatus(entry, info.Status, capturedAt)
303					info.Quota = providerQuotaState(entry, capturedAt)
304					info.CooldownState = serviceProviderCooldown(sc, name, cooldown)
305					info.LastError = statusErrorDetail(info.Status, entry.ConfigError, "service provider config", capturedAt)
306					results[idx] = indexedInfo{idx: idx, info: info}
307					return
308				}
309	
310				probeCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
311				defer cancel()
312				capturedAt := time.Now().UTC()
313				probe := probeProviderStatus(probeCtx, entry, capturedAt)
314				info.Status = probe.status
315				info.ModelCount = probe.modelCount
316				info.Capabilities = probe.caps
317				info.CooldownState = serviceProviderCooldown(sc, name, cooldown)
318				info.Auth = providerAuthStatus(entry, info.Status, capturedAt)
319				info.EndpointStatus = probe.endpointStatuses
320				info.Quota = providerQuotaState(entry, capturedAt)
321				lastErrorSource := "service provider config"
322				if len(info.EndpointStatus) > 0 {
323					lastErrorSource = info.EndpointStatus[0].Source
324				}
325				info.LastError = statusErrorDetail(info.Status, probe.detail, lastErrorSource, capturedAt)
326	
327				results[idx] = indexedInfo{idx: idx, info: info}
328			}(i, name)
329		}
330		wg.Wait()
331	
332		out := make([]ProviderInfo, len(names))
333		for _, r := range results {
334			out[r.idx] = r.info
335		}
336		return out, nil
337	}
