339	// HealthCheck triggers a fresh probe for the named health-check subject and updates internal state.
340	// health.Type is "harness" or "provider".
341	func (s *service) HealthCheck(ctx context.Context, health HealthTarget) error {
342		switch health.Type {
343		case "provider":
344			sc := s.opts.ServiceConfig
345			if sc == nil {
346				return fmt.Errorf("service: no ServiceConfig provided; pass ServiceOptions.ServiceConfig")
347			}
348			entry, ok := sc.Provider(health.Name)
349			if !ok {
350				return fmt.Errorf("service: provider %q not found", health.Name)
351			}
352			probeCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
353			defer cancel()
354			probe := probeProviderStatus(probeCtx, entry, time.Now().UTC())
355			if probe.status == "connected" {
356				return nil
357			}
358			msg := probe.status
359			if probe.detail != "" {
360				msg = probe.detail
361			}
362			return fmt.Errorf("service: provider %q: %s", health.Name, msg)
363	
364		case "harness":
365			statuses := s.registry.Discover()
366			for _, st := range statuses {
367				if st.Name != health.Name {
368					continue
369				}
370				if !st.Available {
371					return fmt.Errorf("service: harness %q unavailable: %s", health.Name, st.Error)
372				}
373				// For subscription harnesses, refresh the quota cache when stale.
374				if health.Name == "claude" {
375					healthCheckRefreshClaudeQuota(ctx)
376				}
377				if health.Name == "codex" {
378					healthCheckRefreshCodexQuota(ctx)
379				}
380				return nil
381			}
382			return fmt.Errorf("service: harness %q not registered", health.Name)
383	
384		default:
385			return fmt.Errorf("service: unknown HealthTarget.Type %q (want \"harness\" or \"provider\")", health.Type)
386		}
387	}
