555	func providerEndpointStatusesFromProbe(entry ServiceProviderEntry, probe providerProbeResult, capturedAt time.Time) []EndpointStatus {
556		endpoints := modelDiscoveryEndpoints(entry)
557		if len(endpoints) == 0 {
558			probe.serverInstance = entry.ServerInstance
559			return []EndpointStatus{endpointStatusFromProbe("default", entry.BaseURL, probe, capturedAt)}
560		}
561		out := make([]EndpointStatus, 0, len(endpoints))
562		for _, endpoint := range endpoints {
563			probe.serverInstance = endpoint.ServerInstance
564			out = append(out, endpointStatusFromProbe(endpoint.Name, endpoint.BaseURL, probe, capturedAt))
565		}
566		return out
567	}
