569	func endpointStatusFromProbe(name, baseURL string, probe providerProbeResult, capturedAt time.Time) EndpointStatus {
570		source := strings.TrimRight(baseURL, "/") + "/models"
571		if baseURL == "" {
572			source = "service provider config"
573		}
574		out := EndpointStatus{
575			Name:           endpointDisplayName(name, baseURL),
576			BaseURL:        baseURL,
577			ServerInstance: serverinstance.Normalize(baseURL, probe.serverInstance),
578			ProbeURL:       source,
579			Status:         endpointStatus(probe.status),
580			Source:         source,
581			CapturedAt:     capturedAt,
582			Fresh:          true,
583			ModelCount:     probe.modelCount,
584			LastError:      statusErrorDetail(probe.status, probe.detail, source, capturedAt),
585		}
586		if out.Status == "connected" {
587			out.LastSuccessAt = capturedAt
588		}
589		return out
590	}
