592	// healthCheckRefreshClaudeQuota refreshes the Claude direct PTY quota cache when
593	// the cached snapshot is older than the default refresh debounce. It is a
594	// best-effort operation: errors are silently discarded so that a claude absence
595	// does not fail HealthCheck.
596	func healthCheckRefreshClaudeQuota(ctx context.Context) {
597		refreshClaudeQuotaCache(ctx, defaultQuotaRefreshDebounce, defaultQuotaRefreshProbeTimeout)
598	}
599	
600	func refreshClaudeQuotaCache(_ context.Context, debounce, timeout time.Duration) {
601		cachePath, err := claudeharness.ClaudeQuotaCachePath()
602		if err != nil {
603			return
604		}
605	
606		snap, _ := claudeharness.ReadClaudeQuotaFrom(cachePath)
607		if snap != nil && claudeharness.DecideClaudeQuotaRouting(snap, time.Now(), debounce).Fresh {
608			// Cache is fresh enough; skip the expensive PTY probe.
609			return
610		}
611	
612		// Cache is absent or stale - run a direct PTY probe with a bounded timeout.
613		windows, acct, probeErr := callHealthCheckClaudeQuotaRefresher(timeout)
614		if probeErr != nil || len(windows) == 0 {
615			return
616		}
617	
618		// Convert QuotaWindow slice to ClaudeQuotaSnapshot. The PTY path returns
619		// percent-based windows; synthesise remaining counts from UsedPercent.
620		newSnap := claudeharness.ClaudeQuotaSnapshot{
621			CapturedAt: time.Now().UTC(),
622			Source:     "pty",
623			Account:    acct,
624			Windows:    append([]harnesses.QuotaWindow(nil), windows...),
625		}
626		for _, w := range windows {
627			switch w.LimitID {
628			case "session":
629				// 5-hour window; use a nominal limit of 100 so Remaining = 100-Used.
630				used := int(w.UsedPercent)
631				newSnap.FiveHourLimit = 100
632				newSnap.FiveHourRemaining = 100 - used
633			case "weekly-all", "weekly-sonnet":
