234	// mapClaudeRoutingPreference translates today's PreferClaude+freshness
235	// decision into the CONTRACT-004 (RoutingPreference, QuotaStateValue)
236	// pair. Legacy semantics: missing snapshot ⇒ Unavailable/Unknown;
237	// stale ⇒ Stale/Blocked ("assume limited"); fresh+PreferClaude ⇒
238	// OK/Available; fresh+!PreferClaude ⇒ Blocked/Blocked.
239	func mapClaudeRoutingPreference(d ClaudeQuotaRoutingDecision) (harnesses.RoutingPreference, harnesses.QuotaStateValue) {
240		if !d.SnapshotPresent {
241			return harnesses.RoutingPreferenceUnknown, harnesses.QuotaUnavailable
242		}
243		if !d.Fresh {
244			return harnesses.RoutingPreferenceBlocked, harnesses.QuotaStale
245		}
246		if d.PreferClaude {
247			return harnesses.RoutingPreferenceAvailable, harnesses.QuotaOK
248		}
249		return harnesses.RoutingPreferenceBlocked, harnesses.QuotaBlocked
250	}
