20	// SyntheticQuotaHarness is an in-memory QuotaHarness used by
21	// service-level tests that previously constructed per-harness snapshot
22	// types directly. SupportedLimitIDs and QuotaFreshness are read from
23	// the values supplied at construction time.
24	type SyntheticQuotaHarness struct {
25		name      string
26		limitIDs  []string
27		freshness time.Duration
28	
29		mu         sync.Mutex
30		status     harnesses.QuotaStatus
31		probeCount int
32		probeLatch <-chan struct{}
33	
34		sf singleflight.Group
35	}
36	
37	// NewSyntheticQuotaHarness builds an in-memory QuotaHarness whose
38	// QuotaStatus returns the supplied status and whose SupportedLimitIDs
39	// returns the supplied set. RefreshQuota is single-flight per harness
40	// instance (concurrent callers share one underlying probe).
41	//
42	// The default QuotaFreshness is 15 minutes; tests that care about a
43	// different window can call SetQuotaFreshness.
44	func NewSyntheticQuotaHarness(name string, status harnesses.QuotaStatus, limitIDs []string) *SyntheticQuotaHarness {
45		return &SyntheticQuotaHarness{
46			name:      name,
47			limitIDs:  append([]string(nil), limitIDs...),
48			freshness: 15 * time.Minute,
49			status:    status,
50		}
51	}
52	
53	// SetQuotaStatus replaces the synthetic status reported by future
54	// QuotaStatus / RefreshQuota calls.
55	func (s *SyntheticQuotaHarness) SetQuotaStatus(status harnesses.QuotaStatus) {
56		s.mu.Lock()
57		defer s.mu.Unlock()
58		s.status = status
59	}
60	
61	// SetQuotaFreshness overrides the freshness window returned by
62	// QuotaFreshness.
63	func (s *SyntheticQuotaHarness) SetQuotaFreshness(d time.Duration) {
64		s.mu.Lock()
65		defer s.mu.Unlock()
66		s.freshness = d
67	}
68	
69	// SetProbeLatch installs a channel that RefreshQuota's probe blocks on
70	// (after incrementing ProbeCount and before returning). Tests use it
71	// to ensure concurrent RefreshQuota callers collide on the same
72	// single-flight cohort. Pass a closed or nil channel to clear the latch.
73	func (s *SyntheticQuotaHarness) SetProbeLatch(ch <-chan struct{}) {
74		s.mu.Lock()
75		defer s.mu.Unlock()
76		s.probeLatch = ch
77	}
