113	// RefreshQuota implements harnesses.QuotaHarness with real single-flight.
114	// Concurrent callers share one underlying probe; ProbeCount increments
115	// once per cohort.
116	func (s *SyntheticQuotaHarness) RefreshQuota(ctx context.Context) (harnesses.QuotaStatus, error) {
117		if err := ctx.Err(); err != nil {
118			return harnesses.QuotaStatus{}, err
119		}
120		v, err, _ := s.sf.Do("refresh", func() (any, error) {
121			s.mu.Lock()
122			s.probeCount++
123			status := s.status
124			latch := s.probeLatch
125			s.mu.Unlock()
126			if latch != nil {
127				select {
128				case <-latch:
129				case <-ctx.Done():
130					return harnesses.QuotaStatus{}, ctx.Err()
131				}
132			}
133			return status, nil
134		})
135		if err != nil {
136			return harnesses.QuotaStatus{}, err
137		}
138		return v.(harnesses.QuotaStatus), nil
139	}
